namespace optiling {

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    VanillaRnnHiddenCustomTilingData tiling;

    // Inputs:
    // x: [T, B, I]
    // h0: [B, H]
    // w_i2h: [H, K] (K = I + H)
    // b_i2h: [H]
    // w_h2o: [O, H]
    // b_h2o: [O]
    const auto *xShape = context->GetInputShape(0);
    const auto *h0Shape = context->GetInputShape(1);
    const auto *w_i2hShape = context->GetInputShape(2);
    const auto *w_h2oShape = context->GetInputShape(4);

    if (xShape->GetOriginShape().GetDimNum() != 3 ||
        h0Shape->GetOriginShape().GetDimNum() != 2 ||
        w_i2hShape->GetOriginShape().GetDimNum() != 2 ||
        w_h2oShape->GetOriginShape().GetDimNum() != 2) {
        return ge::GRAPH_FAILED;
    }

    const uint64_t T = static_cast<uint64_t>(xShape->GetOriginShape().GetDim(0));
    const uint64_t B = static_cast<uint64_t>(xShape->GetOriginShape().GetDim(1));
    const uint64_t I = static_cast<uint64_t>(xShape->GetOriginShape().GetDim(2));
    const uint64_t H = static_cast<uint64_t>(h0Shape->GetOriginShape().GetDim(1));
    const uint64_t O = static_cast<uint64_t>(w_h2oShape->GetOriginShape().GetDim(0));
    const uint64_t K = static_cast<uint64_t>(w_i2hShape->GetOriginShape().GetDim(1));

    // Basic validation (K should equal I + H)
    // We avoid hard failure here to keep robustness.
    // Block mapping: one block per batch where possible.
    uint32_t blockDim = static_cast<uint32_t>(B);
    if (blockDim == 0u) blockDim = 1u;
    if (blockDim > 24u) blockDim = 24u;

    context->SetBlockDim(blockDim);

    tiling.set_T(static_cast<uint32_t>(T));
    tiling.set_B(static_cast<uint32_t>(B));
    tiling.set_I(static_cast<uint32_t>(I));
    tiling.set_H(static_cast<uint32_t>(H));
    tiling.set_O(static_cast<uint32_t>(O));
    tiling.set_K(static_cast<uint32_t>(K));
    tiling.set_blockDim(blockDim);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    // No workspace required
    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

} // namespace optiling

