#include <torch/extension.h>
#include "pytorch_npu_helper.hpp"

at::Tensor vanilla_rnn_hidden_impl_npu(const at::Tensor& x,
                                       const at::Tensor& h0,
                                       const at::Tensor& w_i2h,
                                       const at::Tensor& b_i2h,
